const a = [
  {"id":5223,"text":"Which hormone acts on bones to increase bone resorption and mobilize calcium?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 995.","responses":[{"text":"Ascorbic acid","correct":false,"visible":false},{"text":"Calcitriol","correct":false,"visible":false},{"text":"Tocopherol","correct":false,"visible":false},{"text":"Parathyroid","correct":true,"visible":false},{"text":"Androgens","correct":false,"visible":false}]},{"id":5224,"text":"Which of the following structures pass through the saphenous opening?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 691.","responses":[{"text":"Femoral vein","correct":false,"visible":false},{"text":"Femoral nerve","correct":false,"visible":false},{"text":"Great saphenous vein","correct":true,"visible":false},{"text":"Small saphenous vein and its tributaries","correct":false,"visible":false},{"text":"Superficial inguinal lymph node","correct":false,"visible":false}]},{"id":5225,"text":"What is the chemical name of calcitriol?","explanation":null,"reference":"PubChem. Calcitriol. Accessed September 4, 2022. https://pubchem.ncbi.nlm.nih.gov/compound/5280453","responses":[{"text":"Cholecalciferol","correct":false,"visible":false},{"text":"25-hydroxycholecalciferol","correct":false,"visible":false},{"text":"7-hydroxycholesterol","correct":false,"visible":false},{"text":"1,25-dihydroxycholesterol","correct":false,"visible":false},{"text":"1,25-dihydroxycholecalciferol","correct":true,"visible":false}]},{"id":5226,"text":"Which of the following arteries do not supply blood to the breasts?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018 :318","responses":[{"text":"Lateral thoracic artery","correct":false,"visible":false},{"text":"Intercostal arteries","correct":false,"visible":false},{"text":"Internal thoracic artery","correct":false,"visible":false},{"text":"Thoracoacromial artery","correct":false,"visible":false},{"text":"Highest thoracic artery","correct":true,"visible":false}]},{"id":5233,"text":"Which of the following body parts is most commonly affected in the case of osteoarthritis in men?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1198","responses":[{"text":"Hands","correct":false,"visible":false},{"text":"Lumbar vertebrae","correct":false,"visible":false},{"text":"Knees","correct":false,"visible":false},{"text":"Hips","correct":true,"visible":false},{"text":"Spine","correct":false,"visible":false}]},{"id":5235,"text":"Which of the following statements is not true regarding the extensor digitorum?","explanation":null,"reference":"1. Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 775-778.\r\n2. Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 224-226","responses":[{"text":"It has common extensor origin","correct":false,"visible":false},{"text":"It is a superficial muscle on the back of the forearm","correct":false,"visible":false},{"text":"It is supplied by the anterior interosseous nerve","correct":true,"visible":false},{"text":"It is an extender of the interphalangeal and metacarpophalangeal joint","correct":false,"visible":false},{"text":"It is inserted on the distal phalanx","correct":false,"visible":false}]},{"id":5239,"text":"Which of the following is incorrect for the attachment of a muscle to the radius?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 743, 767, 771, 775, 778.","responses":[{"text":"Flexor pollicis longus on the upper two-thirds of the lateral surface","correct":true,"visible":false},{"text":"Pronator teres on the middle of the lateral surface","correct":false,"visible":false},{"text":"Biceps brachii on the radial tuberosity","correct":false,"visible":false},{"text":"Supinator on the upper part of the lateral surface","correct":false,"visible":false},{"text":"Brachioradialis on the lowest part of the lateral surface","correct":false,"visible":false}]},{"id":5240,"text":"Which of the folowing is a non-contractile protein in skeletal muscle fibers?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 79,81.","responses":[{"text":"Troponin","correct":false,"visible":false},{"text":"Actin","correct":false,"visible":false},{"text":"Myosin","correct":false,"visible":false},{"text":"Tropomyosin","correct":false,"visible":false},{"text":"Titin","correct":true,"visible":false}]},{"id":5241,"text":"Which of the following is a branch of the lateral cord of the brachial plexus?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 731","responses":[{"text":"Thoracodorsal nerve","correct":false,"visible":false},{"text":"Upper subscapular nerve","correct":false,"visible":false},{"text":"Medial cutaneous nerve of arm","correct":false,"visible":false},{"text":"Musculocutaneous nerve","correct":true,"visible":false},{"text":"Medial pectoral nerve","correct":false,"visible":false}]},{"id":5244,"text":"A 35-year-old woman presents to the emergency room after suffering from a road traffic accident. The doctor on duty obtains an anteroposterior view of her elbow joint via X-ray. A translucent transverse gap between her arm and forearm bones is seen in the X-ray. The patient becomes worried after seeing this. The doctor tells her that this is a normal anatomical structure. Which of the following anatomical features does this gap represent?","explanation":null,"reference":null,"responses":[{"text":"Articular cartilage","correct":true,"visible":false},{"text":"Olecranon fossa","correct":false,"visible":false},{"text":"Trochlear notch","correct":false,"visible":false},{"text":"Fracture","correct":false,"visible":false},{"text":"Epiphyseal plate","correct":false,"visible":false}]},{"id":5245,"text":"Radial artery in the forearm is marked by:","explanation":null,"reference":null,"responses":[{"text":"Neck of the radius lateral to the biceps tendon","correct":true,"visible":false},{"text":"Neck of the radius medial to brachialis","correct":false,"visible":false},{"text":"Neck of the radius lateral to brachialis","correct":false,"visible":false},{"text":"Neck of the radius medial to biceps brachii","correct":false,"visible":false},{"text":"Neck of the radius lateral to coracoradialis","correct":false,"visible":false}]},{"id":5400,"text":"Every third position of the triple helical structure of alpha chain of collagen is occupied by glycine because it:","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 45","responses":[{"text":"Confers rigidity to the collagen molecule","correct":false,"visible":false},{"text":"Exists in D and L forms","correct":false,"visible":false},{"text":"Is hydroxylated easily","correct":false,"visible":false},{"text":"Is a polar amino acid","correct":false,"visible":false},{"text":"Is small enough to be accommodated in the central core of the triple helix","correct":true,"visible":false}]},{"id":5401,"text":"The lateral group of superficial inguinal lymph nodes receives superficial vessels from:","explanation":null,"reference":null,"responses":[{"text":"External genitalia","correct":false,"visible":false},{"text":"Anterior abdominal wall","correct":false,"visible":false},{"text":"Medial compartment of thigh","correct":false,"visible":false},{"text":"Back below level of iliac crest","correct":true,"visible":false},{"text":"Umbilicus","correct":false,"visible":false}]},{"id":5402,"text":"On entering the spinal cord, the fast pain signals are carried by which of the following pathways to the brain?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 615","responses":[{"text":"Cerebrospinal tract","correct":false,"visible":false},{"text":"Vestibulocochlear tract","correct":false,"visible":false},{"text":"Spinothalamic tract","correct":false,"visible":false},{"text":"Paleospinothalamic tract","correct":false,"visible":false},{"text":"Neospinothalamic tract","correct":true,"visible":false}]},{"id":5403,"text":"Which of the following statements is accurate regarding the femoral region?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 710, 713,","responses":[{"text":"The medial compartment of femoral sheath contains femoral nerve","correct":false,"visible":false},{"text":"Femoral canal is the lateral compartment of femoral sheath","correct":false,"visible":false},{"text":"Femoral sheath is continuous superiorly with transversalis fascia and iliac fascia","correct":true,"visible":false},{"text":"The femoral artery, vein, and nerve are surrounded by the femoral sheath","correct":false,"visible":false},{"text":"Femoral hernia arises from the lateral compartment of femoral sheath","correct":false,"visible":false}]},{"id":5404,"text":"Which of the following muscles is not a part of the hamstring group?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 709, 728.","responses":[{"text":"Hamstring portion of adductor magnus","correct":false,"visible":false},{"text":"Short head of biceps femoris","correct":true,"visible":false},{"text":"Long head of biceps femoris","correct":false,"visible":false},{"text":"Semitendinosus","correct":false,"visible":false},{"text":"Semimembranosus","correct":false,"visible":false}]},{"id":5405,"text":"The small saphenous vein terminates into which of the following veins?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 694.","responses":[{"text":"Great saphenous vein","correct":false,"visible":false},{"text":"Popliteal vein","correct":true,"visible":false},{"text":"Femoral vein","correct":false,"visible":false},{"text":"Anterior tibial","correct":false,"visible":false},{"text":"Profunda femoris vein","correct":false,"visible":false}]},{"id":5406,"text":"The saphenous nerve is a branch of which of the following nerves?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 773, 775.","responses":[{"text":"Obturator nerve","correct":false,"visible":false},{"text":"Tibial nerve","correct":false,"visible":false},{"text":"Femoral nerve","correct":true,"visible":false},{"text":"Lateral cutaneous nerve of thigh","correct":false,"visible":false},{"text":"Common peroneal nerve","correct":false,"visible":false}]},{"id":5407,"text":"At the postsynaptic membrane in the neuromuscular junction, action potentials are transmitted from axons to muscle fibers by the binding of acetylcholine to its receptor. Which of the following channels open as a result of this binding?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 94.","responses":[{"text":"Ryanodine channels","correct":false,"visible":false},{"text":"Mg⁺² channels","correct":false,"visible":false},{"text":"Dihydropyridine channels","correct":false,"visible":false},{"text":"Na⁺ channels","correct":true,"visible":false},{"text":"K⁺ channels","correct":false,"visible":false}]},{"id":5414,"text":"What is the term used for the type of fracture caused by an underlying disease?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1184.","responses":[{"text":"Buckle fracture","correct":false,"visible":false},{"text":"Pathologic fracture","correct":true,"visible":false},{"text":"Comminuted fracture","correct":false,"visible":false},{"text":"Greenstick fracture","correct":false,"visible":false},{"text":"Compound fracture","correct":false,"visible":false}]},{"id":5418,"text":"The extracellular matrix is composed of an interlocking meshwork of heteropolysaccharides and fibrous proteins. What are the proteins that contain covalently linked glycosaminoglycans called?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 111.","responses":[{"text":"Proteoglycans","correct":true,"visible":false},{"text":"Chondroitin sulphate","correct":false,"visible":false},{"text":"Hyaluronic acid","correct":false,"visible":false},{"text":"Heparin sulphate","correct":false,"visible":false},{"text":"Keratan sulphate","correct":false,"visible":false}]},{"id":5419,"text":"Which of the following nerve(s) supply the gripping muscle of the forearm?","explanation":null,"reference":"1. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4013148/\r\n2. Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 771.","responses":[{"text":"Ulnar nerve","correct":false,"visible":false},{"text":"Radial nerve","correct":false,"visible":false},{"text":"Medial and radial nerves","correct":false,"visible":false},{"text":"Median and ulnar nerves","correct":true,"visible":false},{"text":"Median nerve","correct":false,"visible":false}]},{"id":5420,"text":"Which of the following statements is correct regarding the brachial plexus?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 731, 735.","responses":[{"text":"Median nerve is the branch of  the medial cord, and innervates the flexor carpi ulnaris muscles","correct":false,"visible":false},{"text":"Axillary nerve is the terminal branch of lateral cord","correct":false,"visible":false},{"text":"Ulnar nerve is the branch of the posterior cord","correct":false,"visible":false},{"text":"Musculocutaneous nerve is the largest terminal branch of the lateral cord","correct":true,"visible":false},{"text":"Radial nerve is a branch of the lateral cord","correct":false,"visible":false}]},{"id":5421,"text":"Which of the following is the appropriate muscle that causes adduction at the wrist joint?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 278.","responses":[{"text":"Flexor digitorum profundus","correct":false,"visible":false},{"text":"Flexor digitorum superficialis","correct":false,"visible":false},{"text":"Palmaris longus","correct":false,"visible":false},{"text":"Flexor carpi radialis","correct":false,"visible":false},{"text":"Flexor carpi ulnaris","correct":true,"visible":false}]},{"id":5422,"text":"Which of the following muscles is invested by the clavipectoral fascia?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 158.","responses":[{"text":"Subclavius muscle","correct":true,"visible":false},{"text":"Rhomboid minor","correct":false,"visible":false},{"text":"Latissimus dorsi","correct":false,"visible":false},{"text":"Levator scapulae","correct":false,"visible":false},{"text":"Rhomboid major","correct":false,"visible":false}]},{"id":5423,"text":"Which action would fail in case of paralysis of the quadriceps femoris muscle?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 584.","responses":[{"text":"Adduction at the hip","correct":false,"visible":false},{"text":"Extension of the hip","correct":false,"visible":false},{"text":"Flexion at the knee","correct":false,"visible":false},{"text":"Medial rotation of the knee","correct":false,"visible":false},{"text":"Extension at the knee","correct":true,"visible":false}]},{"id":5424,"text":"Which of the following is accurate regarding the femoral triangle?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 710.","responses":[{"text":"Medial border is formed by the lateral margin of sartorius","correct":false,"visible":false},{"text":"The inguinal ligament is the base of the triangle","correct":true,"visible":false},{"text":"It is a wedge shaped depression formed by muscles in the thigh at the junction between the upper limb and anterior abdominal wall","correct":false,"visible":false},{"text":"The lateral border is formed by the medial margin of adductor longus","correct":false,"visible":false},{"text":"The floor is medially fomed by the iliopsoas muscle","correct":false,"visible":false}]},{"id":5426,"text":"Which of the following receptors is particular for pain?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 587.","responses":[{"text":"Osmoreceptors","correct":false,"visible":false},{"text":"Mechanoreceptors","correct":false,"visible":false},{"text":"Photoreceptors","correct":false,"visible":false},{"text":"Nociceptors","correct":true,"visible":false},{"text":"Chemoreceptors","correct":false,"visible":false}]},{"id":5427,"text":"A student becomes worried about a person who is unable to dorsiflex his foot at the ankle joint. Which of the following nerve supplies the dorsiflexor of the foot?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 747, 749.","responses":[{"text":"Deep peroneal nerve","correct":true,"visible":false},{"text":"Tibial nerve","correct":false,"visible":false},{"text":"Saphenous nerve","correct":false,"visible":false},{"text":"Sural nerve","correct":false,"visible":false},{"text":"Superficial peroneal nerve","correct":false,"visible":false}]},{"id":5428,"text":"Which of the following muscles is most deeply placed in the calf region?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 755, 760.","responses":[{"text":"Tibialis posterior","correct":true,"visible":false},{"text":"Flexor digitorum longus","correct":false,"visible":false},{"text":"Plantaris","correct":false,"visible":false},{"text":"Soleus","correct":false,"visible":false},{"text":"Flexor hallucis longus","correct":false,"visible":false}]},{"id":5434,"text":"Which part of the skeleton is commonly involved in tuberculous osteomyelitis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1186.","responses":[{"text":"Knee","correct":false,"visible":false},{"text":"Hip","correct":false,"visible":false},{"text":"Elbow","correct":false,"visible":false},{"text":"Spine","correct":true,"visible":false},{"text":"Neck of the femur","correct":false,"visible":false}]},{"id":5437,"text":"What is the prevention and treatment for senile and postmenopausal osteoporosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1179, 1180.","responses":[{"text":"Glucocorticoids","correct":false,"visible":false},{"text":"Physical inactivity","correct":false,"visible":false},{"text":"Calcium and vitamin D supplementation","correct":true,"visible":false},{"text":"Bed rest","correct":false,"visible":false},{"text":"Bone marrow transplant","correct":false,"visible":false}]},{"id":5445,"text":"To which disk do the actin filaments get attached and extend in both directions?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 79.","responses":[{"text":"I","correct":false,"visible":false},{"text":"Z","correct":true,"visible":false},{"text":"H","correct":false,"visible":false},{"text":"M","correct":false,"visible":false},{"text":"A","correct":false,"visible":false}]},{"id":5447,"text":"Which of the following statements is correct regarding the route of the great saphenous vein?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 655.","responses":[{"text":"Posterior to the medial malleolus","correct":false,"visible":false},{"text":"Joins the femoral vein superficial to the fascia lata","correct":false,"visible":false},{"text":"Anterior to the medial malleolus","correct":true,"visible":false},{"text":"Passes up the lateral side of the leg","correct":false,"visible":false},{"text":"Anterior to the medial condyle of the tibia and femur","correct":false,"visible":false}]},{"id":5448,"text":"Which sesamoid bone is present in the quadriceps femoris tendon?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 678.","responses":[{"text":"Pisiform","correct":false,"visible":false},{"text":"Ulna","correct":false,"visible":false},{"text":"Fibula","correct":false,"visible":false},{"text":"Patella","correct":true,"visible":false},{"text":"Scaphoid","correct":false,"visible":false}]},{"id":5452,"text":"A 21-year-old man presents to the outpatient department with a complaint of receiving an injury on the wrist joint. He informs he had fallen from the motorbike against his hand. Which of the following is true regarding the injury of the median nerve at the wrist joint?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 260.","responses":[{"text":"Loss of pronation","correct":false,"visible":false},{"text":"Loss of sensation on the dorsal surface only","correct":false,"visible":false},{"text":"Inability to oppose the thumb","correct":true,"visible":false},{"text":"Wrist drop","correct":false,"visible":false},{"text":"Loss of cutaneous supply in the palm","correct":false,"visible":false}]},{"id":5458,"text":"Which of the following is accurate regarding the muscles of the pectoral girdle?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 167, 170.","responses":[{"text":"Anterior or pectoral group of muscles include the pectoralis major, pectoralis minor, subclavius, and the deltoid","correct":false,"visible":false},{"text":"Muscles of the anterior group of axio-appendicular muscles are also called thoraco-appendicular muscles","correct":true,"visible":false},{"text":"The serratus anterior muscle is part of the posterior muscle group","correct":false,"visible":false},{"text":"The lattisimus dorsi is a part of the anterior muscle group","correct":false,"visible":false},{"text":"Posterior group is divided into two subgroups","correct":false,"visible":false}]},{"id":5459,"text":"A 40-year-old woman with arthritis came to the outpatient department with complaints of impaired sensation over the lateral 3.5 digits on the palm of her hand, weakness, and wasting of the thenar muscle. Which of the following nerve is involved in this?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 255, 256.","responses":[{"text":"Median nerve","correct":true,"visible":false},{"text":"Ulnar nerve","correct":false,"visible":false},{"text":"Palmar branch of the median nerve","correct":false,"visible":false},{"text":"Radial nerve","correct":false,"visible":false},{"text":"Posterior interosseous nerve","correct":false,"visible":false}]},{"id":5460,"text":"Which of the following structures passes through and divides the greater sciatic foramen?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 568.","responses":[{"text":"Tendon of the obturator internus muscle","correct":false,"visible":false},{"text":"Sciatic nerve","correct":false,"visible":false},{"text":"Piriformis muscle","correct":true,"visible":false},{"text":"Posterior cutaneous nerve of thigh","correct":false,"visible":false},{"text":"Pudendal nerve","correct":false,"visible":false}]},{"id":5461,"text":"The ulnar nerve is marked by what joints in hand?","explanation":null,"reference":null,"responses":[{"text":"Medial to pisiform bone","correct":false,"visible":false},{"text":"Back of base of medial epicondyle","correct":false,"visible":false},{"text":"Middle of medial border of arm","correct":false,"visible":false},{"text":"Lateral to pisiform bone","correct":true,"visible":false},{"text":"Junction of anterior 1/3 and posterior 1/3 of the lateral wall of axilla","correct":false,"visible":false}]},{"id":5462,"text":"Which of the following statement is inappropriate regarding the subsartorial canal?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018:  715.","responses":[{"text":"It commences above at the apex of femoral triangle","correct":false,"visible":false},{"text":"Ends at the opening in adductor magnus","correct":false,"visible":false},{"text":"Bounded laterally by the vastus medialis","correct":false,"visible":false},{"text":"Bounded anteromedially by the sartorius muscles","correct":false,"visible":false},{"text":"Bounded posteriorly by the adductor longus only","correct":true,"visible":false}]},{"id":5483,"text":"Which of the following veins pass through the deltopectoral triangle?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 688.","responses":[{"text":"Brachial vein","correct":false,"visible":false},{"text":"Axillary vein","correct":false,"visible":false},{"text":"Subclavian vein","correct":false,"visible":false},{"text":"Cephalic vein","correct":true,"visible":false},{"text":"Basilic vein","correct":false,"visible":false}]},{"id":5485,"text":"Which of the following veins combine to form the axillary vein?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 188.","responses":[{"text":"Basilic vein and cephalic vein","correct":false,"visible":false},{"text":"Brachial vein and cephalic vein","correct":false,"visible":false},{"text":"Basilic vein and brachial vein","correct":true,"visible":false},{"text":"Basilic vein and radial vein","correct":false,"visible":false},{"text":"Basilic vein and subclavian vein","correct":false,"visible":false}]},{"id":5491,"text":"What is the most common complication of osteoporosis?","explanation":null,"reference":null,"responses":[{"text":"Endocarditis","correct":false,"visible":false},{"text":"Pulmonary embolism","correct":false,"visible":false},{"text":"Osteosarcoma","correct":false,"visible":false},{"text":"Kyphoscoliosis","correct":true,"visible":false},{"text":"Hearing impairment","correct":false,"visible":false}]},{"id":5492,"text":"In which of the following conditions is the remarkable feature of yellow and grayish membrane on the larynx or the pharynx seen?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 361.","responses":[{"text":"Acute respiratory tract infection","correct":false,"visible":false},{"text":"Diphtheria","correct":true,"visible":false},{"text":"Viral Infection","correct":false,"visible":false},{"text":"Sore throat","correct":false,"visible":false},{"text":"Tonsillitis","correct":false,"visible":false}]},{"id":5493,"text":"Which of the following muscles is involved in shrugging the shoulders?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 170, 171.","responses":[{"text":"Trapezius","correct":true,"visible":false},{"text":"Deltoid","correct":false,"visible":false},{"text":"Supraspinatus","correct":false,"visible":false},{"text":"Pectoralis major/minor","correct":false,"visible":false},{"text":"Teres major/minor","correct":false,"visible":false}]},{"id":5495,"text":"What is the approximate length of a sarcomere in a resting muscle fiber?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 85.","responses":[{"text":"4 µm","correct":false,"visible":false},{"text":"1 µm","correct":false,"visible":false},{"text":"6 µm","correct":false,"visible":false},{"text":"2 µm","correct":true,"visible":false},{"text":"3 µm","correct":false,"visible":false}]},{"id":5496,"text":"What type of fibril-forming collagen is the most abundant in cartilage?","explanation":null,"reference":"1. Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 131.\r\n\r\n2. Young B, O’Dowd G, Woodford P. Wheater’s Functional Histology: A Text and Colour Atlas. 6th ed. Churchill Livingston/Elsevier; 2014: 66.","responses":[{"text":"Collagen type V","correct":false,"visible":false},{"text":"Collagen type II","correct":true,"visible":false},{"text":"Collagen type IV","correct":false,"visible":false},{"text":"Collagen type III","correct":false,"visible":false},{"text":"Collagen type I","correct":false,"visible":false}]},{"id":5497,"text":"Which of the following cells are responsible for maintaining the bone matrix once it has been formed?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 158.","responses":[{"text":"Osteoblasts","correct":false,"visible":false},{"text":"Osteoclasts","correct":false,"visible":false},{"text":"Osteocytes","correct":true,"visible":false},{"text":"Both osteoblasts and osteoclasts","correct":false,"visible":false},{"text":"Fibroblasts","correct":false,"visible":false}]},{"id":5499,"text":"Which of the following is not a complication of chronic osteomyelitis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1186.","responses":[{"text":"Cor pulmonale","correct":true,"visible":false},{"text":"Sepsis","correct":false,"visible":false},{"text":"Endocarditis","correct":false,"visible":false},{"text":"Pathologic fracture","correct":false,"visible":false},{"text":"Secondary amyloidosis","correct":false,"visible":false}]},{"id":5500,"text":"How much additional potential difference is created when the sodium-potassium pump transfers three sodium ions outside the cell and two potassium ions inside the cell?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 67.","responses":[{"text":"-4 mV","correct":true,"visible":false},{"text":"-5 mV","correct":false,"visible":false},{"text":"-3 mV","correct":false,"visible":false},{"text":"-2 mV","correct":false,"visible":false},{"text":"-1 mV","correct":false,"visible":false}]},{"id":5501,"text":"Which of the following cannot stimulate smooth muscles?","explanation":null,"reference":"(1) Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 106, 108.\r\n\r\n(2) Hafen BB, Burns B. Physiology, smooth muscle. In: StatPearls. StatPearls Publishing; 2022. Accessed September 15, 2022. http://www.ncbi.nlm.nih.gov/books/NBK526125/","responses":[{"text":"Somatic nerves","correct":true,"visible":false},{"text":"Prostaglandins","correct":false,"visible":false},{"text":"Oxytocin","correct":false,"visible":false},{"text":"Autonomic nerves","correct":false,"visible":false},{"text":"Internal stretching of smooth muscle walls due to a disease","correct":false,"visible":false}]},{"id":5503,"text":"At what time do the primary ossification centers appear in long bones?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 349.","responses":[{"text":"Organogenesis period","correct":false,"visible":false},{"text":"12th week of intrauterine life","correct":true,"visible":false},{"text":"3rd week of intrauterine life","correct":false,"visible":false},{"text":"At birth","correct":false,"visible":false},{"text":"Soon after birth","correct":false,"visible":false}]},{"id":5504,"text":"What is the term used for the pieces of dislodged cartilage seen in the joints in case of osteoarthritis?","explanation":null,"reference":"1. Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 196.\r\n2. Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1198.","responses":[{"text":"Joint mice","correct":true,"visible":false},{"text":"Bouchard nodes","correct":false,"visible":false},{"text":"Involucrum","correct":false,"visible":false},{"text":"Sequestrum","correct":false,"visible":false},{"text":"Heberden nodes","correct":false,"visible":false}]},{"id":5506,"text":"Which artery runs along with the radial nerve in the radial groove (spiral groove) of the humerus?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 146.","responses":[{"text":"Brachial artery","correct":false,"visible":false},{"text":"Radial artery","correct":false,"visible":false},{"text":"Ulnar artery","correct":false,"visible":false},{"text":"Profunda brachii artery","correct":true,"visible":false},{"text":"Axillary artery","correct":false,"visible":false}]},{"id":5508,"text":"Which of the following is not a branch of the tibial nerve of the leg?","explanation":null,"reference":"1. Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 710, 761.\r\n2. Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 621, 622.","responses":[{"text":"Sural nerve","correct":false,"visible":false},{"text":"Medial calcaneal nerve","correct":false,"visible":false},{"text":"Nerve to soleus","correct":false,"visible":false},{"text":"Medial plantar nerve","correct":false,"visible":false},{"text":"Saphenous nerve","correct":true,"visible":false}]},{"id":5509,"text":"Fenn effect is produced when the myosin head binds to actin filaments. What is true about this effect?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 84.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Work done is inversely proportional to ATP cleaved","correct":false,"visible":false},{"text":"Work done is directly proportional to Mg++ and ATP cleaved","correct":false,"visible":false},{"text":"Work done is directly proportional to ATP cleaved","correct":true,"visible":false},{"text":"Work done is inversely proportional to Mg++ and ATP cleaved","correct":false,"visible":false}]},{"id":5510,"text":"Which of the following muscles contribute(s) to the formation of the floor of the femoral triangle?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 564.","responses":[{"text":"Adductor longus","correct":false,"visible":false},{"text":"Pectineus","correct":false,"visible":false},{"text":"Iliopsoas, pectineus and adductor longus","correct":true,"visible":false},{"text":"Iliopsoas and pectineus","correct":false,"visible":false},{"text":"Iliopsoas","correct":false,"visible":false}]},{"id":5511,"text":"Injury to which of the following nerve causes winging of the scapula?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 179.","responses":[{"text":"Nerve to subclavius","correct":false,"visible":false},{"text":"Long thoracic nerve","correct":true,"visible":false},{"text":"Medial pectoral nerve","correct":false,"visible":false},{"text":"Lateral pectoral nerve","correct":false,"visible":false},{"text":"Dorsal scapular nerve","correct":false,"visible":false}]},{"id":5512,"text":"Which vaccine is recommended specifically for the elderly?","explanation":null,"reference":null,"responses":[{"text":"Measles","correct":false,"visible":false},{"text":"BCG","correct":false,"visible":false},{"text":"Hepatitis B","correct":false,"visible":false},{"text":"Hepatitis C","correct":false,"visible":false},{"text":"Influenza virus","correct":true,"visible":false}]},{"id":5515,"text":"What does a comminuted fracture mean?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1183.","responses":[{"text":"An open fracture","correct":false,"visible":false},{"text":"A fracture with splintered bones","correct":true,"visible":false},{"text":"A fracture with unaligned bones","correct":false,"visible":false},{"text":"A closed fracture","correct":false,"visible":false},{"text":"A simple fracture","correct":false,"visible":false}]},{"id":5522,"text":"Which of the following muscles is present in the bicipital groove?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 146.","responses":[{"text":"Short head of triceps brachii","correct":false,"visible":false},{"text":"Long head of biceps brachii","correct":true,"visible":false},{"text":"Deltoid","correct":false,"visible":false},{"text":"Long head of triceps brachii","correct":false,"visible":false},{"text":"Short head of biceps brachii","correct":false,"visible":false}]},{"id":5523,"text":"What is the function of calcitonin?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 1003.","responses":[{"text":"Increases plasma calcium concentration","correct":false,"visible":false},{"text":"Increases plasma calcitriol concentration","correct":false,"visible":false},{"text":"Decreases plasma magnesium concentration","correct":false,"visible":false},{"text":"Increases plasma potassium concentration","correct":false,"visible":false},{"text":"Decreases plasma calcium concentration","correct":true,"visible":false}]},{"id":5524,"text":"The parathyroid hormone increases the plasma concentration of which of the following mineral?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 1000.","responses":[{"text":"Sodium","correct":false,"visible":false},{"text":"Calcium","correct":true,"visible":false},{"text":"Phosphate","correct":false,"visible":false},{"text":"Potassium","correct":false,"visible":false},{"text":"Magnesium","correct":false,"visible":false}]},{"id":5525,"text":"Which lymph node(s) drain into the central axillary lymph nodes?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 188, 189.","responses":[{"text":"Subscapular nodes only","correct":false,"visible":false},{"text":"Lateral axillary, pectoral and subscapular nodes","correct":true,"visible":false},{"text":"Lateral axillary nodes only","correct":false,"visible":false},{"text":"Apical nodes only","correct":false,"visible":false},{"text":"Pectoral nodes only","correct":false,"visible":false}]},{"id":5526,"text":"Which nerve is injured when the shaft of the clavicle is fractured, causing neck pain on the side of the neck?","explanation":null,"reference":"Labronici PJ, Segall FS, Martins BA, et al. Clavicle fractures - incidence of supraclavicular nerve injury. Rev Bras Ortop. 2013;48(4):317-321. doi:10.1016/j.rboe.2012.09.009","responses":[{"text":"Dorsal scapular nerve","correct":false,"visible":false},{"text":"Median nerve","correct":false,"visible":false},{"text":"Axillary nerve","correct":false,"visible":false},{"text":"Supraclavicular nerve","correct":true,"visible":false},{"text":"Radial nerve","correct":false,"visible":false}]},{"id":5527,"text":"Which form of vitamin D is made in the skin and consumed in the diet?","explanation":null,"reference":"Calcium I of M (US) C to RDRI for VD and, Ross AC, Taylor CL, Yaktine AL, Valle HBD. Overview of Vitamin d. National Academies Press (US); 2011. Accessed September 9, 2022. https://www.ncbi.nlm.nih.gov/books/NBK56061/","responses":[{"text":"Calciferol","correct":false,"visible":false},{"text":"Calcitriol","correct":false,"visible":false},{"text":"Cholecalciferol","correct":true,"visible":false},{"text":"Cholesterol","correct":false,"visible":false},{"text":"Ergocalciferol","correct":false,"visible":false}]},{"id":5528,"text":"What is chondroitin sulfate made of?","explanation":"**Chondroitin sulfate** is made of **N-acetylgalactosamine and glucuronic acid**. These two sugar molecules alternate in a chain to form the structure of chondroitin sulfate, a key component of cartilage.","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 159.","responses":[{"text":"Glucuronic acid+ iduronic acid","correct":false,"visible":false},{"text":"N-acetylgalactosamine + glucuronic acid","correct":true,"visible":false},{"text":"N-acetylglucosamine + iduronic acid","correct":false,"visible":false},{"text":"N-acetylglucosamine + glucuronic acid","correct":false,"visible":false},{"text":"N-acetylgalactosamine + iduronic acid","correct":false,"visible":false}]},{"id":5529,"text":"Which substance is necessary for the strong and instantaneous binding of the myosin head with actin?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 83.","responses":[{"text":"Magnesium ions only","correct":false,"visible":false},{"text":"ATP and calcium ions","correct":false,"visible":false},{"text":"Calcium ions only","correct":false,"visible":false},{"text":"ATP and magnesium ions","correct":true,"visible":false},{"text":"ATP only","correct":false,"visible":false}]},{"id":5530,"text":"Which ligament is damaged when the separation of shoulder joint occurs with clavicular fracture from the acromion side?","explanation":null,"reference":"1. Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 284.\r\n\r\n2. Kiel J, Kaiser K. Acromioclavicular joint injury. In: StatPearls. StatPearls Publishing; 2022. Accessed September 9, 2022. http://www.ncbi.nlm.nih.gov/books/NBK493188/","responses":[{"text":"Coracoclavicular and acromioclavicular ligament","correct":true,"visible":false},{"text":"Coracoclavicular ligament","correct":false,"visible":false},{"text":"Costoclavicular ligament","correct":false,"visible":false},{"text":"Sternoclavicular ligament","correct":false,"visible":false},{"text":"Glenohumeral coracoid ligament","correct":false,"visible":false}]},{"id":5531,"text":"Which teratogenic drug causes malformation of the limbs?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 372.","responses":[{"text":"Acetyl salicylic acid","correct":false,"visible":false},{"text":"Paracetamol","correct":false,"visible":false},{"text":"Acetaminophen","correct":false,"visible":false},{"text":"Amoxicillin","correct":false,"visible":false},{"text":"Thalidomide","correct":true,"visible":false}]},{"id":5532,"text":"What is the anatomical position of the nipple?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 322.","responses":[{"text":"3rd intercostal space","correct":false,"visible":false},{"text":"4th intercostal space lateral to the mid-clavicular line","correct":true,"visible":false},{"text":"3rd intercostal space lateral to the mid-clavicular line","correct":false,"visible":false},{"text":"6th intercostal space","correct":false,"visible":false},{"text":"2nd intercostal space","correct":false,"visible":false}]},{"id":5533,"text":"Which cofactor is necessary for hydroxylation during collagen synthesis?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 47.","responses":[{"text":"Cholecalciferol","correct":false,"visible":false},{"text":"Folate","correct":false,"visible":false},{"text":"Calcitriol","correct":false,"visible":false},{"text":"Retinol","correct":false,"visible":false},{"text":"Ascorbate","correct":true,"visible":false}]},{"id":5534,"text":"Which long bone of the lower limb has the medial malleolus as its normal anatomical part?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 680.","responses":[{"text":"Talus","correct":false,"visible":false},{"text":"Fibula","correct":false,"visible":false},{"text":"Navicular bone","correct":false,"visible":false},{"text":"Femur","correct":false,"visible":false},{"text":"Tibia","correct":true,"visible":false}]},{"id":5535,"text":"Which nerve is damaged during the impairment of foot eversion?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 764.","responses":[{"text":"Sural nerve","correct":false,"visible":false},{"text":"Medial plantar nerve","correct":false,"visible":false},{"text":"Medial calcaneal nerve","correct":false,"visible":false},{"text":"Common peroneal nerve","correct":true,"visible":false},{"text":"Tibial nerve","correct":false,"visible":false}]},{"id":5536,"text":"Which of the following is the most abundant protein in bones?","explanation":null,"reference":"Young B, O’Dowd G, Woodford P. Wheater’s Functional Histology: A Text and Colour Atlas. 6th ed. Churchill Livingston/Elsevier; 2014: 183.","responses":[{"text":"Collagen type I","correct":true,"visible":false},{"text":"Elastin","correct":false,"visible":false},{"text":"Collagen type II","correct":false,"visible":false},{"text":"Collagen type III","correct":false,"visible":false},{"text":"Fibronectin","correct":false,"visible":false}]},{"id":5538,"text":"Which muscle is most likely to be impaired when a person is unable to flex, abduct, and laterally rotate his thigh?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 704.","responses":[{"text":"Gracilis","correct":false,"visible":false},{"text":"Obturator externus","correct":false,"visible":false},{"text":"Sartorius","correct":true,"visible":false},{"text":"Adductor longus","correct":false,"visible":false},{"text":"Gluteus medius","correct":false,"visible":false}]},{"id":5539,"text":"Which of the following nerves is damaged in carpal tunnel syndrome?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 237.","responses":[{"text":"Median and ulnar nerves","correct":false,"visible":false},{"text":"Ulnar nerve","correct":false,"visible":false},{"text":"Median nerve","correct":true,"visible":false},{"text":"Radial nerve","correct":false,"visible":false},{"text":"Axillary nerve","correct":false,"visible":false}]},{"id":5540,"text":"Which of the following is true about the absorption of dietary calcium?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 388.","responses":[{"text":"Is enhanced by phytate","correct":false,"visible":false},{"text":"Occurs in the terminal part of the ileum","correct":false,"visible":false},{"text":"Is enhanced by calciferol","correct":true,"visible":false},{"text":"Is independent of protein","correct":false,"visible":false},{"text":"Is enhanced by parathyroid hormone directly","correct":false,"visible":false}]},{"id":5541,"text":"Which of the following structures lie deep to the flexor retinaculum?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 220.","responses":[{"text":"Median artery","correct":false,"visible":false},{"text":"Ulnar artery","correct":false,"visible":false},{"text":"Flexor digitorum superficialis","correct":true,"visible":false},{"text":"Cutaneous branch of median nerve","correct":false,"visible":false},{"text":"Radial artery","correct":false,"visible":false}]},{"id":5542,"text":"A lady came to the outpatient department (OPD) with a hard palpable mass in the upper outer quadrant of the breast. Which lymph nodes are most involved?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 188.","responses":[{"text":"Subscapular nodes","correct":false,"visible":false},{"text":"Deltopectoral nodes","correct":false,"visible":false},{"text":"Supraclavicular nodes","correct":false,"visible":false},{"text":"Pectoral nodes","correct":true,"visible":false},{"text":"Parasternal nodes","correct":false,"visible":false}]},{"id":5543,"text":"Which bony structure cannot be palpated in the anatomical snuffbox?","explanation":null,"reference":"Hallett S, Ashurst JV. Anatomy, shoulder and upper limb, hand anatomical snuff box. StatPearls. Published 2022. Accessed September 19, 2022. http://www.ncbi.nlm.nih.gov/books/NBK482228/","responses":[{"text":"Base of 1st metacarpal","correct":false,"visible":false},{"text":"Trapezium","correct":false,"visible":false},{"text":"Base of 2nd metacarpal","correct":true,"visible":false},{"text":"Radial styloid process","correct":false,"visible":false},{"text":"Scaphoid","correct":false,"visible":false}]},{"id":5547,"text":"Nernst equation describes the relationship of diffusion potential to which of the following across a semipermeable membrane?","explanation":"The **Nernst equation** describes the relationship of diffusion potential to the **concentration of a single ion** across a semipermeable membrane. It is used to calculate the equilibrium potential for an ion based on its concentration gradient across the membrane.\r\n\r\n---\r\n\r\nConcentration of multiple ions: The Nernst equation is specific to a single ion. The Goldman equation, on the other hand, considers multiple ions.\r\nFacilitated diffusion: While facilitated diffusion is a type of membrane transport, the Nernst equation specifically deals with the equilibrium potential of a single ion, not the mechanism of transport.\r\nCo-transport: This refers to the simultaneous transport of two or more ions or molecules in the same direction across a membrane, which is not what the Nernst equation describes.\r\nCounter transport: This refers to the simultaneous transport of two or more ions or molecules in opposite directions across a membrane, which is also not what the Nernst equation describes.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 56-57.","responses":[{"text":"Concentration of a single ion","correct":true,"visible":false},{"text":"Facilitated diffusion","correct":false,"visible":false},{"text":"Counter transport","correct":false,"visible":false},{"text":"Concentration of multiple ions","correct":false,"visible":false},{"text":"Co-transport","correct":false,"visible":false}]},{"id":5548,"text":"Which of the following is not included in the diagnostic criteria of rheumatoid arthritis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1200-1202.","responses":[{"text":"Rheumatoid nodules","correct":false,"visible":false},{"text":"Morning stiffness","correct":false,"visible":false},{"text":"Asymmetrical arthritis","correct":true,"visible":false},{"text":"Serum rheumatoid factor","correct":false,"visible":false},{"text":"Arthritis of three or more joint areas","correct":false,"visible":false}]},{"id":5549,"text":"Which fibers transmit slow pain?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 614.","responses":[{"text":"A-delta fibers","correct":false,"visible":false},{"text":"A-beta fibers","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"A-alpha fibers","correct":false,"visible":false},{"text":"C fibers","correct":true,"visible":false}]},{"id":5550,"text":"Which neurotransmitter inhibits both slow and fast pain transmission at the presynaptic and postsynaptic junctions in the dorsal horn of the spinal cord?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 617.","responses":[{"text":"Serotonin","correct":true,"visible":false},{"text":"Substance P","correct":false,"visible":false},{"text":"Acetylcholine","correct":false,"visible":false},{"text":"Glutamate","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":5551,"text":"Against which of the following are autoantibodies produced in Lambert-Eaton syndrome?","explanation":"In **Lambert-Eaton syndrome**, autoantibodies are produced against **presynaptic calcium channels**. These autoantibodies interfere with the release of acetylcholine at the neuromuscular junction, leading to muscle weakness.\r\n\r\n---\r\n\r\nAutoantibodies against muscle proteins are not the cause of Lambert-Eaton syndrome, although they may be implicated in other autoimmune conditions affecting muscle.\r\n\r\nAutoantibodies against acetylcholine receptors are characteristic of myasthenia gravis, not Lambert-Eaton syndrome.\r\n\r\nAutoantibodies against potassium or sodium channels are not associated with Lambert-Eaton syndrome. They may be implicated in other neurological conditions.","reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1236.","responses":[{"text":"Acetylcholine channels","correct":false,"visible":false},{"text":"Sodium channels","correct":false,"visible":false},{"text":"Presynaptic calcium channels","correct":true,"visible":false},{"text":"Potassium channels","correct":false,"visible":false},{"text":"Muscle proteins","correct":false,"visible":false}]},{"id":5552,"text":"A patient came to the outpatient department with a complaint that when he laterally rotates and adducts the thumb, his hand appeared flat and ape-like. Which nerve is likely to be injured?","explanation":null,"reference":"Halliday NL, Chung HM. BRS: Gross Anatomy. 9th ed. Wolters Kluwer; 2019: 313.","responses":[{"text":"Radial nerve","correct":false,"visible":false},{"text":"Median nerve","correct":true,"visible":false},{"text":"Anterior interosseous nerve","correct":false,"visible":false},{"text":"Ulnar nerve","correct":false,"visible":false},{"text":"Axillary nerve","correct":false,"visible":false}]},{"id":5553,"text":"Which statement is true regarding the sodium-potassium ATPase pump?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 59.","responses":[{"text":"Ions pass through it by diffusion","correct":false,"visible":false},{"text":"Maintains the concentration difference of ions across the cell membrane","correct":true,"visible":false},{"text":"Pumps three sodium into the cell and two potassium ions out of the cell","correct":false,"visible":false},{"text":"It is not inhibited by metabolic poisons","correct":false,"visible":false},{"text":"Has no role in the resting membrane potential of the cell","correct":false,"visible":false}]},{"id":5554,"text":"Which muscle is involved in forming the boundaries of the popliteal fossa?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 609-610.","responses":[{"text":"Obturator externus","correct":false,"visible":false},{"text":"Popliteus muscle","correct":false,"visible":false},{"text":"Gastrocnemius","correct":true,"visible":false},{"text":"Quadratus femoris","correct":false,"visible":false},{"text":"Sartorius","correct":false,"visible":false}]},{"id":5555,"text":"Which muscle is the prime mover of medial rotation of the arm?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer: 2018: 176.","responses":[{"text":"Infraspinatus","correct":false,"visible":false},{"text":"Subscapularis","correct":true,"visible":false},{"text":"Supraspinatus","correct":false,"visible":false},{"text":"Teres minor","correct":false,"visible":false},{"text":"Teres major","correct":false,"visible":false}]},{"id":5556,"text":"Which of the following is the feature of the claw hand?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 239.","responses":[{"text":"Loss of sensation at the thenar eminence","correct":false,"visible":false},{"text":"Hyperextension of metacarpophalangeal joints and flexion of interphangeal joints","correct":true,"visible":false},{"text":"Pronation of the forearm","correct":false,"visible":false},{"text":"Flexion of the wrist joint","correct":false,"visible":false},{"text":"Loss of supination","correct":false,"visible":false}]},{"id":5557,"text":"Which structure is involved in excitation-contraction coupling?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 97.","responses":[{"text":"The epimysium is excited before excitation of the sarcolemma","correct":false,"visible":false},{"text":"Mitochondria provides the calcium ions for contraction","correct":false,"visible":false},{"text":"ATP molecules are provided by the sarcoplasmic reticulum","correct":false,"visible":false},{"text":"Action potential from the muscle membrane travels to the interior of cell through T-Tubules","correct":true,"visible":false},{"text":"The myosin and actin bind because of calcium-calmodulin binding to actin","correct":false,"visible":false}]},{"id":5558,"text":"A child is born with multiple fractures without any history of trauma. The doctor tells that it is due to a disease that leads to defective collagen synthesis causing the long bones to bend. What is this disease most likely to be?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1175-1180.","responses":[{"text":"Osteoporosis","correct":false,"visible":false},{"text":"Osteogenesis imperfecta","correct":true,"visible":false},{"text":"Osteopetrosis","correct":false,"visible":false},{"text":"Rickets","correct":false,"visible":false},{"text":"Osteomalacia","correct":false,"visible":false}]},{"id":5560,"text":"Which of the following structures is not present in the axilla?","explanation":null,"reference":"1. Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 183.\r\n2. Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 142.","responses":[{"text":"Tail of the breast","correct":false,"visible":false},{"text":"Trunks of the brachial plexus","correct":true,"visible":false},{"text":"Axillary vein","correct":false,"visible":false},{"text":"Fat","correct":false,"visible":false},{"text":"Axillary artery","correct":false,"visible":false}]},{"id":5577,"text":"Which statement is true about myasthenia gravis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1225.","responses":[{"text":"Caused by clostridium botulinum","correct":false,"visible":false},{"text":"Antibodies against acetylcholine receptors are formed","correct":true,"visible":false},{"text":"Antibodies against presynaptic calcium channels are formed","correct":false,"visible":false},{"text":"Antibodies against muscles are formed","correct":false,"visible":false},{"text":"The release of acetylcholine is blocked","correct":false,"visible":false}]},{"id":5578,"text":"Which artery is not a branch of the posterior tibial artery?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 761, 762.","responses":[{"text":"Medial plantar artery","correct":false,"visible":false},{"text":"Nutrient artery of tibia","correct":false,"visible":false},{"text":"Peroneal artery","correct":false,"visible":false},{"text":"Lateral plantar artery","correct":false,"visible":false},{"text":"Nutrient artery of fibula","correct":true,"visible":false}]},{"id":5579,"text":"Which of the following spinal segments form the femoral nerve?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 710.","responses":[{"text":"L2, L3, L4","correct":true,"visible":false},{"text":"L4, L5, S1, S2","correct":false,"visible":false},{"text":"L2, L3","correct":false,"visible":false},{"text":"L5, L6, L7","correct":false,"visible":false},{"text":"L5, S1, S2","correct":false,"visible":false}]},{"id":5580,"text":"Which nerve is accompanied by the great saphenous vein?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 700.","responses":[{"text":"Femoral nerve","correct":false,"visible":false},{"text":"Peroneal nerve","correct":false,"visible":false},{"text":"Saphenous nerve","correct":true,"visible":false},{"text":"Tibial nerve","correct":false,"visible":false},{"text":"Sural nerve","correct":false,"visible":false}]},{"id":5581,"text":"Which of the following is not one of the key principles of health education?","explanation":null,"reference":"Dow Lecture Slides. Locomotor Module, Subject: Community Medicine, Topic: Health Promotion and Health Education, Sub-topic: Health Education.","responses":[{"text":"Creating habits","correct":true,"visible":false},{"text":"Learning by doing","correct":false,"visible":false},{"text":"Change of behavior","correct":false,"visible":false},{"text":"Good relations","correct":false,"visible":false},{"text":"Knowing customs","correct":false,"visible":false}]},{"id":5582,"text":"A 34-year-old man is brought to the emergency room with a stab wound injury in his axilla. A neurologic examination reveals the injury has caused the posterior cord of the brachial plexus to be damaged. Which of the following structures is most likely affected?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 180-181, 193.","responses":[{"text":"Deltoid","correct":true,"visible":false},{"text":"Pectoralis major","correct":false,"visible":false},{"text":"Subclavius","correct":false,"visible":false},{"text":"Rhomboid major","correct":false,"visible":false},{"text":"Supraspinatus","correct":false,"visible":false}]},{"id":5583,"text":"Which disease is specifically common in older people?","explanation":null,"reference":"Dow Lecture Slides. Locomotor Module, Subject: Community Medicine, Topic: Elderly Health, Sub-topic: Problems of Aging Population-Common Illnesses in Elderly.","responses":[{"text":"Reproductive health issues","correct":false,"visible":false},{"text":"Pneumonia","correct":false,"visible":false},{"text":"Dementia","correct":true,"visible":false},{"text":"Tuberculosis","correct":false,"visible":false},{"text":"Sexually transmitted diseases","correct":false,"visible":false}]},{"id":5585,"text":"A person sustained an injury that damaged the quadrangular space. After this, the person was unable to abduct and extend his arm. Which muscle is likely to be damaged?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 180, 193.","responses":[{"text":"Supraspinatus","correct":false,"visible":false},{"text":"Deltoid","correct":true,"visible":false},{"text":"Subscapularis","correct":false,"visible":false},{"text":"Rhomboid major","correct":false,"visible":false},{"text":"Infraspinatus","correct":false,"visible":false}]},{"id":5586,"text":"Which of the following nerve passes through the quadrangular space?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 719.","responses":[{"text":"Dorsal scapular nerve","correct":false,"visible":false},{"text":"Thoracodorsal nerve","correct":false,"visible":false},{"text":"Long thoracic nerve","correct":false,"visible":false},{"text":"Nerve to subclavius","correct":false,"visible":false},{"text":"Axillary nerve","correct":true,"visible":false}]},{"id":5587,"text":"A 34-old man presents to the outpatient department with a complaint of inability to extend his leg at the knee joint. Which of the following nerves is most likely to be affected?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 705.","responses":[{"text":"Peroneal nerve","correct":false,"visible":false},{"text":"Sciatic nerve","correct":false,"visible":false},{"text":"Tibial nerve","correct":false,"visible":false},{"text":"Femoral nerve","correct":true,"visible":false},{"text":"Obturator nerve","correct":false,"visible":false}]},{"id":5588,"text":"Which of the following nerves supply the medial side of the thigh?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 707.","responses":[{"text":"Tibial nerve","correct":false,"visible":false},{"text":"Sural nerve","correct":false,"visible":false},{"text":"Sciatic nerve","correct":false,"visible":false},{"text":"Obturator nerve","correct":true,"visible":false},{"text":"Femoral nerve","correct":false,"visible":false}]},{"id":5589,"text":"Which of the following bones form the pelvic girdle?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 668, 671.","responses":[{"text":"Ilium, sacrum and coccyx","correct":false,"visible":false},{"text":"Hip bone with femur","correct":false,"visible":false},{"text":"Ischium, pubis and ilium","correct":true,"visible":false},{"text":"Hip bone with sacrum and coccyx","correct":false,"visible":false},{"text":"Ischium, sacrum and coccyx","correct":false,"visible":false}]},{"id":5590,"text":"A person with a history of nerve injury walks with a limp and is unable to properly lift his left foot off the ground with a straight posture while walking. Which of the following muscles is affected?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 740, 741.","responses":[{"text":"Left gluteus medius","correct":false,"visible":false},{"text":"Left gluteus maximus","correct":false,"visible":false},{"text":"Right gluteus medius","correct":true,"visible":false},{"text":"Right gluteus minimus","correct":false,"visible":false},{"text":"Right gluteus maximus","correct":false,"visible":false}]},{"id":5591,"text":"Where is the stethoscope placed during blood pressure measurement for percussion?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 212.","responses":[{"text":"Radial artery over cubital fossa","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"2.5 cm above the cubital fossa","correct":false,"visible":false},{"text":"Ulnar artery at the side of wrist joint","correct":false,"visible":false},{"text":"Brachial artery over cubital fossa","correct":true,"visible":false}]},{"id":5592,"text":"Which of the following muscles is supplied by the deep peroneal nerve?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 750, 756, 757.","responses":[{"text":"Peroneus longus","correct":false,"visible":false},{"text":"Tibialis Anterior","correct":true,"visible":false},{"text":"Peroneus brevis","correct":false,"visible":false},{"text":"Tibialis posterior","correct":false,"visible":false},{"text":"Plantaris","correct":false,"visible":false}]},{"id":5593,"text":"Which of the following conditions would result from injury to the common peroneal nerve?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 764.","responses":[{"text":"Inability to plantarflex the big toe","correct":false,"visible":false},{"text":"Inability to plantarflex and invert the foot","correct":false,"visible":false},{"text":"Inability to plantarflex the foot","correct":false,"visible":false},{"text":"Inability to evert the foot","correct":true,"visible":false},{"text":"Inability to invert the foot","correct":false,"visible":false}]},{"id":5594,"text":"In which process do osteoclasts break the bone?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 995.","responses":[{"text":"Bone resorption","correct":true,"visible":false},{"text":"Bone demineralization","correct":false,"visible":false},{"text":"Bone remodeling","correct":false,"visible":false},{"text":"Bone mineralization","correct":false,"visible":false},{"text":"Bone modeling","correct":false,"visible":false}]},{"id":5595,"text":"In which of the following conditions does the high turnover osteoporosis occur?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1180.","responses":[{"text":"Low calcium and low vitamin D","correct":false,"visible":false},{"text":"Low estrogen","correct":true,"visible":false},{"text":"Low progesterone","correct":false,"visible":false},{"text":"High progesterone","correct":false,"visible":false},{"text":"High estrogen","correct":false,"visible":false}]},{"id":5596,"text":"Health promotion is the science and art of helping people modify their lifestyles to move toward a state of optimal health. Which of the following factors has the maximum effect on building long-term positive changes?","explanation":null,"reference":"Dow Lecture Slides. Locomotor Module, Subject: Community Medicine, Topic: Health Promotion and Health Education, Sub-topic: Health Promotion.","responses":[{"text":"Supportive environment","correct":true,"visible":false},{"text":"Health education session","correct":false,"visible":false},{"text":"Funding","correct":false,"visible":false},{"text":"Behavior","correct":false,"visible":false},{"text":"Publicity","correct":false,"visible":false}]},{"id":5597,"text":"Which nerve supplies the skin of the medial one and half digits and the palm?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 807.","responses":[{"text":"Deep branch of the ulnar nerve","correct":false,"visible":false},{"text":"Recurrent branch of the median nerve","correct":false,"visible":false},{"text":"Superficial branch of the ulnar nerve","correct":true,"visible":false},{"text":"Palmar cutaneous branch of the median nerve","correct":false,"visible":false},{"text":"Radial nerve","correct":false,"visible":false}]},{"id":5598,"text":"Which of the following amino acids is present at every third position in collagen?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 45.","responses":[{"text":"Lysine","correct":false,"visible":false},{"text":"Glycine","correct":true,"visible":false},{"text":"Hydroxyproline","correct":false,"visible":false},{"text":"Glutamate","correct":false,"visible":false},{"text":"Proline","correct":false,"visible":false}]},{"id":5613,"text":"A 40-year-old woman, after having surgery of varicose veins, noticed that there is a loss of sensation of the medial border of the foot. Which nerve has been lesioned?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 700.","responses":[{"text":"Common peroneal","correct":false,"visible":false},{"text":"Sural","correct":false,"visible":false},{"text":"Tibial","correct":false,"visible":false},{"text":"Superficial peroneal","correct":false,"visible":false},{"text":"Saphenous","correct":true,"visible":false}]},{"id":5625,"text":"Which of these is the largest protein in skeletal muscle fibers?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 79.","responses":[{"text":"Titin","correct":true,"visible":false},{"text":"Tropomyosin","correct":false,"visible":false},{"text":"Actin","correct":false,"visible":false},{"text":"Troponin","correct":false,"visible":false},{"text":"Myosin","correct":false,"visible":false}]},{"id":5697,"text":"Which of the following nerves supply the flexor digitorum muscles?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 218, 219.","responses":[{"text":"Median and ulnar nerve","correct":true,"visible":false},{"text":"Median nerve","correct":false,"visible":false},{"text":"Median and radial nerve","correct":false,"visible":false},{"text":"Ulnar nerve","correct":false,"visible":false},{"text":"Radial nerve","correct":false,"visible":false}]},{"id":5698,"text":"Which of the following statements is most appropriate regarding the actions of the sartorius muscle?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 704.","responses":[{"text":"Flexes, abducts, and laterally rotates the thigh at hip joint, and medially rotates the leg at knee joint","correct":true,"visible":false},{"text":"Laterally rotates the thigh at the hip joint and medially rotates the leg at knee joint","correct":false,"visible":false},{"text":"Flexes and abducts thigh at hip joint","correct":false,"visible":false},{"text":"Flexes the knee joint","correct":false,"visible":false},{"text":"Sartorius draws the lower limb into tailor's position when sitting on a stool","correct":false,"visible":false}]},{"id":5699,"text":"Osteosarcoma is a malignant tumor of bone. Which of the following statements regarding osteosarcoma is correct?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1188.","responses":[{"text":"75% occur in adults above 60 years of age","correct":false,"visible":false},{"text":"Histologically it is characterized by a mosaic pattern of bone formation","correct":false,"visible":false},{"text":"Mutations in tumor suppressor genes play no role in pathogenesis","correct":false,"visible":false},{"text":"Brodie's abscess is a diagnostic feature on X-ray","correct":false,"visible":false},{"text":"50% occur in the region of the knee","correct":true,"visible":false}]},{"id":5700,"text":"Which of the following part or branch of the brachial plexus receives a contribution from the C8 spinal nerve?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 193.","responses":[{"text":"Lateral pectoral nerve","correct":false,"visible":false},{"text":"Lateral cord","correct":false,"visible":false},{"text":"Ulnar nerve","correct":true,"visible":false},{"text":"Suprascapular nerve","correct":false,"visible":false},{"text":"Nerve to rhomboid muscles","correct":false,"visible":false}]},{"id":5701,"text":"A patient was brought to the outpatient department with complaints of pain and swelling in the right leg. On examination, dorsiflexion at the ankle joint increased the severity of the pain. Which of the following muscles is not involved in dorsiflexion?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 750.","responses":[{"text":"Tibialis anterior","correct":false,"visible":false},{"text":"Peroneus tertius","correct":false,"visible":false},{"text":"Extensor digitorum longus","correct":false,"visible":false},{"text":"Extensor hallucis longus","correct":false,"visible":false},{"text":"Peroneus longus","correct":true,"visible":false}]},{"id":5702,"text":"There are two types of pain, fast and slow pain. The fast type of pain is carried by which of the following fibers?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 615.","responses":[{"text":"A-beta","correct":false,"visible":false},{"text":"1B","correct":false,"visible":false},{"text":"A-alpha","correct":false,"visible":false},{"text":"A-delta","correct":true,"visible":false},{"text":"C","correct":false,"visible":false}]},{"id":5703,"text":"Which of the following muscles is supplied by the ulnar nerve?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 193.","responses":[{"text":"Flexor carpi radialis","correct":false,"visible":false},{"text":"Palmaris longus","correct":false,"visible":false},{"text":"Flexor carpi ulnaris","correct":true,"visible":false},{"text":"Flexor digitorum superficialis","correct":false,"visible":false},{"text":"Pronator teres","correct":false,"visible":false}]},{"id":5704,"text":"Which of the following marks the level of the inferior angle of the scapula, located under the skin?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 151.","responses":[{"text":"1st lumbar vertebrae","correct":false,"visible":false},{"text":"12th thoracic vertebrae","correct":false,"visible":false},{"text":"5th thoracic vertebral spine","correct":false,"visible":false},{"text":"7th thoracic vertebral spine","correct":true,"visible":false},{"text":"Crest of Ilium","correct":false,"visible":false}]},{"id":5705,"text":"Which of the following statements is correct regarding the lateral half of the clavicle?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 143.","responses":[{"text":"Resembles an elongated capital \"S\"","correct":false,"visible":false},{"text":"Convex anteriorly with a triangular acromial end","correct":false,"visible":false},{"text":"Convex posteriorly with a triangular acromial end","correct":false,"visible":false},{"text":"Concave anteriorly with a flat acromial end","correct":true,"visible":false},{"text":"Convexo-concave","correct":false,"visible":false}]},{"id":5706,"text":"The flexor carpi radialis is innervated by which of the following of nerves?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 218.","responses":[{"text":"Radial nerve","correct":false,"visible":false},{"text":"Anterior interosseus nerve","correct":false,"visible":false},{"text":"Musculocutaneous nerve","correct":false,"visible":false},{"text":"Deep branch of radial nerve","correct":false,"visible":false},{"text":"Median nerve","correct":true,"visible":false}]},{"id":5707,"text":"Which of the following is the most common causative agent in skeletal syphilis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1186.","responses":[{"text":"Group B streptococci","correct":false,"visible":false},{"text":"Salmonella typhi","correct":false,"visible":false},{"text":"Treponema pallidum","correct":true,"visible":false},{"text":"Staphylococcus aureus","correct":false,"visible":false},{"text":"Mycobacterium tuberculosis","correct":false,"visible":false}]},{"id":5708,"text":"Which of the following is appropriate regarding the structure passing superficial to extensor retinaculum in the upper limb?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 227.","responses":[{"text":"Extensor carpi radialis longus","correct":false,"visible":false},{"text":"Abductor pollicis longus","correct":false,"visible":false},{"text":"Extensor carpi radialis brevis","correct":false,"visible":false},{"text":"Superficial branch of radial nerve","correct":true,"visible":false},{"text":"Extensor carpi ulnaris","correct":false,"visible":false}]},{"id":5709,"text":"Regarding the development of clavicle, which of the following is incorrect?","explanation":null,"reference":null,"responses":[{"text":"It unifies within membranes and proteins via solely intramembranous ossification","correct":true,"visible":false},{"text":"It ossifies from 2 primary centers of ossification","correct":false,"visible":false},{"text":"It is the 1st bone to begin ossification","correct":false,"visible":false},{"text":"It is the last to finish ossification at around 21-25 years of age","correct":false,"visible":false},{"text":"Ossification begins between the 5th and 6th weeks of gestation","correct":false,"visible":false}]},{"id":5770,"text":"Dorsiflexion of the foot is done by which of the following muscles?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 221, 750, 757.","responses":[{"text":"Extensor indicis","correct":false,"visible":false},{"text":"Tibialis anterior","correct":false,"visible":false},{"text":"Extensor digitorum longus","correct":false,"visible":false},{"text":"Tibialis posterior","correct":false,"visible":false},{"text":"Combination of extensor digitorum longus and tibialis anterior","correct":true,"visible":false}]},{"id":5771,"text":"Which of the following muscles are innervated by both obturator and sciatic nerve?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 708.","responses":[{"text":"Biceps femoris","correct":false,"visible":false},{"text":"Adductor magnus","correct":true,"visible":false},{"text":"Semitendinosus","correct":false,"visible":false},{"text":"Pectineus","correct":false,"visible":false},{"text":"Adductor longus","correct":false,"visible":false}]},{"id":5772,"text":"Which of the following arteries form the plantar arterial arch or deep plantar arch?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 778, 779.","responses":[{"text":"Dorsalis pedis artery","correct":false,"visible":false},{"text":"Lateral plantar and dorsalis pedis arteries","correct":true,"visible":false},{"text":"Lateral plantar artery","correct":false,"visible":false},{"text":"Medial plantar artery","correct":false,"visible":false},{"text":"Medial plantar and lateral plantar arteries","correct":false,"visible":false}]},{"id":5773,"text":"Which of the following is the neurotransmitter that is released from neuromuscular junctions and causes the opening of ion channels that causes depolarization of the muscle fiber?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 93.","responses":[{"text":"Epinephrine","correct":false,"visible":false},{"text":"Acetylcholine","correct":true,"visible":false},{"text":"Dopamine","correct":false,"visible":false},{"text":"Serotonin","correct":false,"visible":false},{"text":"Glutamine","correct":false,"visible":false}]},{"id":5774,"text":"Which of the following statements is correct regarding the scapula?","explanation":null,"reference":"1. Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 146, 151.\r\n2. Halliday NL, M C Harold, Won C Kyung. BRS: Gross Anatomy. 10th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2020: 280.","responses":[{"text":"Scapular spine is subcutaneous","correct":true,"visible":false},{"text":"Scapular notch transmits supra scapular vessels","correct":false,"visible":false},{"text":"Coracoid process can be felt inside supraclavicular fossa","correct":false,"visible":false},{"text":"Inferior border is the thinnest border","correct":false,"visible":false},{"text":"Inferior angle lies at the level of T6 vertebrae","correct":false,"visible":false}]},{"id":5775,"text":"An athlete has a knee injury, and the doctor performs a \"drawer test\" by pulling and pushing on the leg with the knee flexed. If the leg translates anteriorly i.e. \"gives\" or moves anteriorly when the leg is pulled anteriorly, what joint structure is most likely injured?","explanation":null,"reference":"1. Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 822.\r\n2. Halliday NL, M C Harold, Won C Kyung. BRS: Gross Anatomy. 10th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2020: 234.","responses":[{"text":"Medial mensicus","correct":false,"visible":false},{"text":"Posterior cruciate ligament","correct":false,"visible":false},{"text":"Lateral collateral ligament","correct":false,"visible":false},{"text":"Anterior cruciate ligament","correct":true,"visible":false},{"text":"Medial cruciate ligament","correct":false,"visible":false}]},{"id":5776,"text":"The fascia lata receives the insertion of which of the following muscles?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 725.","responses":[{"text":"Gluteus maximus - gluteus medius","correct":false,"visible":false},{"text":"Tensor fascia lata - gluteus minimus","correct":false,"visible":false},{"text":"Gluteus maximus - sartorius","correct":false,"visible":false},{"text":"Tensor fascia lata - upper and superior fibers of gluteus maximus","correct":true,"visible":false},{"text":"Tensor fascia lata - gluteus medius","correct":false,"visible":false}]},{"id":5777,"text":"Which ligament limits extension at the hip joint?","explanation":null,"reference":null,"responses":[{"text":"Ischiofemoral","correct":false,"visible":false},{"text":"Pubofemoral","correct":false,"visible":false},{"text":"Zona orbicularis","correct":false,"visible":false},{"text":"Iliofemoral","correct":true,"visible":false},{"text":"Ligamentum capitis femoris","correct":false,"visible":false}]},{"id":5778,"text":"Which of the following statements regarding the muscle spindle is correct?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 687, 688.","responses":[{"text":"Responds to tension in the muscle","correct":false,"visible":false},{"text":"Are innervated only by type II fibers","correct":false,"visible":false},{"text":"Responds to rate of change in the length of muscle","correct":true,"visible":false},{"text":"Receives motor innervation from alpha fibers","correct":false,"visible":false},{"text":"Are extrafusal","correct":false,"visible":false}]},{"id":5779,"text":"Which of the following features is related to the coracobrachialis muscle?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 204.","responses":[{"text":"Quadrangular space of arm","correct":false,"visible":false},{"text":"Musculocutaneous nerve","correct":true,"visible":false},{"text":"Bicipital aponeurosis","correct":false,"visible":false},{"text":"Radial groove","correct":false,"visible":false},{"text":"Bicipital groove","correct":false,"visible":false}]},{"id":5832,"text":"A 5-year-old hemophilic child presents with osteomyelitis. The most likely pathogen, in this case, is which of the following?","explanation":null,"reference":null,"responses":[{"text":"Hemophilus","correct":false,"visible":false},{"text":"Staphylococcus aureus","correct":true,"visible":false},{"text":"Salmonella","correct":false,"visible":false},{"text":"Streptococcus pneumoniae","correct":false,"visible":false},{"text":"E.coli","correct":false,"visible":false}]},{"id":5860,"text":"What is the importance of the curvatures of the clavicle bone?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 143.","responses":[{"text":"Make the bone more suitable for articulation with the scapula","correct":false,"visible":false},{"text":"Make the bone more resistant","correct":true,"visible":false},{"text":"Help the bone in articulation with the membrane","correct":false,"visible":false},{"text":"Make the bone shorter","correct":false,"visible":false},{"text":"Make the bone subcutaneous","correct":false,"visible":false}]},{"id":5861,"text":"Which of the following is the appropriate nerve supply of the biceps femoris muscle?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 729.","responses":[{"text":"Common peroneal nerve","correct":false,"visible":false},{"text":"Tibial and common peroneal nerves","correct":true,"visible":false},{"text":"Tibial and sciatic nerves","correct":false,"visible":false},{"text":"Tibial nerve","correct":false,"visible":false},{"text":"Sciatic nerve","correct":false,"visible":false}]},{"id":5866,"text":"A 22-year-old man has persistent lower back pain and stiffness that diminishes with activity. Over the next 10 years, he develops hip and shoulder pain with decreased range of motion. On physical examination at age 42, he has diminished lumbar lordosis with decreased lumbar spine mobility. He has no other major medical problems. Which of the following is the most likely diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Ankylosing spondylitis","correct":false,"visible":false},{"text":"Osteoarthritis","correct":true,"visible":false},{"text":"Rheumatoid arthritis","correct":false,"visible":false},{"text":"Lyme disease","correct":false,"visible":false},{"text":"Calcium pyrophosphate dihydrate deposition disease","correct":false,"visible":false}]},{"id":5868,"text":"A malignant melanoma (cancer) of the skin covering the buttocks may spread via the lymphatics through which of the following nodes?","explanation":null,"reference":"Mikhael M, Khan YS. Anatomy, abdomen and pelvis, lymphatic drainage. In: StatPearls. StatPearls Publishing; 2022. Accessed July 25, 2022. http://www.ncbi.nlm.nih.gov/books/NBK557720/","responses":[{"text":"Horizontal group of superficial inguinal node","correct":true,"visible":false},{"text":"Posterior axillary node","correct":false,"visible":false},{"text":"Vertical group of superficial inguinal node","correct":false,"visible":false},{"text":"Popliteal node","correct":false,"visible":false},{"text":"Internal iliac node","correct":false,"visible":false}]},{"id":5869,"text":"What is the most common cause of injury to the sciatic nerve in the gluteal region?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 741.","responses":[{"text":"Improper intramuscular injections","correct":true,"visible":false},{"text":"Dislocations of hip joint","correct":false,"visible":false},{"text":"Fractures of femur neck","correct":false,"visible":false},{"text":"Stab wounds","correct":false,"visible":false},{"text":"Pressure from pelvic masses","correct":false,"visible":false}]},{"id":5870,"text":"Which of the following muscles is supplied by the medial plantar nerve?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 771, 772.","responses":[{"text":"First dorsal interosseous","correct":false,"visible":false},{"text":"Abductor hallucis","correct":true,"visible":false},{"text":"Abductor digiti minimi","correct":false,"visible":false},{"text":"Adductor hallucis","correct":false,"visible":false},{"text":"First plantar interosseous","correct":false,"visible":false}]},{"id":5871,"text":"Which of the following is true regarding the composition of collagen type I?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 105.","responses":[{"text":"Coiled structure","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Double helix structure","correct":false,"visible":false},{"text":"Tertiary structure","correct":false,"visible":false},{"text":"Triple helix structure","correct":true,"visible":false}]},{"id":5873,"text":"A 6-year-old child was diagnosed with a case of rickets. A drug was added to calcium supplements and milk for the correction of rickets in that child. Which of the following drugs was given to this patient?","explanation":null,"reference":null,"responses":[{"text":"Gallium nitride","correct":false,"visible":false},{"text":"Cholecalciferol","correct":true,"visible":false},{"text":"Teriparatide","correct":false,"visible":false},{"text":"Plicamycin","correct":false,"visible":false},{"text":"Calcitriol","correct":false,"visible":false}]},{"id":5885,"text":"Which of the following muscles act as an extensor and lateral rotator of the arm?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 174.","responses":[{"text":"Latissimus dorsi","correct":false,"visible":false},{"text":"Sternocostal fibers of pectoralis major","correct":false,"visible":false},{"text":"Anterior fibers of deltoid","correct":false,"visible":false},{"text":"Teres major","correct":false,"visible":false},{"text":"Posterior fibers of deltoid","correct":true,"visible":false}]},{"id":5887,"text":"Which one of the following is the most cost-effective intervention of health promotion?","explanation":null,"reference":"Dow Lecture Slides. Locomotor Module, Subject: Community Medicine, Topic: Health Promotion and Health Education.","responses":[{"text":"Life-style change","correct":false,"visible":false},{"text":"Food fortification","correct":false,"visible":false},{"text":"Nutrition education","correct":false,"visible":false},{"text":"Environmental modification","correct":false,"visible":false},{"text":"Health education","correct":true,"visible":false}]},{"id":5888,"text":"When an action potential is generated, it propagates along the excitable cell membrane. Which of the following regarding its propagation is correct?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 71, 72.","responses":[{"text":"Can spread in only one direction from initial stimulus","correct":false,"visible":false},{"text":"Propagates due to opening of ligand gated ion channels along the membrane","correct":false,"visible":false},{"text":"Spreads along the membrane due to opening of K⁺ channels","correct":false,"visible":false},{"text":"Action potential does not propagate along the membrane","correct":false,"visible":false},{"text":"Can spread in both directions of the membrane from initial stimulus","correct":true,"visible":false}]},{"id":5889,"text":"Myasthenia gravis develops due to the production of antibodies against which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1125.","responses":[{"text":"Acetylcholine receptors","correct":true,"visible":false},{"text":"Sarcoplasmic reticulum","correct":false,"visible":false},{"text":"Presynaptic terminal","correct":false,"visible":false},{"text":"Muscle golgi apparatus","correct":false,"visible":false},{"text":"Acetylcholinesterase","correct":false,"visible":false}]},{"id":5890,"text":"Which of the following is a tributary of the great saphenous vein?","explanation":null,"reference":"Halliday NL, M C Harold, Won C Kyung. BRS: Gross Anatomy. 10th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2020: 240.","responses":[{"text":"Sural vein","correct":false,"visible":false},{"text":"Short saphenous vein","correct":false,"visible":false},{"text":"Superficial epigastric vein","correct":true,"visible":false},{"text":"Femoral vein","correct":false,"visible":false},{"text":"Popliteal vein","correct":false,"visible":false}]},{"id":5891,"text":"Which of the following statements is incorrect regarding the clavicle?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 143.","responses":[{"text":"It is the only long bone which ossifies in membrane","correct":false,"visible":false},{"text":"It is subcutaneous throughout","correct":false,"visible":false},{"text":"Its medial end is flattened and articulates with the clavicular notch of the sternum","correct":true,"visible":false},{"text":"The subclavian groove gives insertion to the subclavius muscles","correct":false,"visible":false},{"text":"It is the first bone in the body to ossify","correct":false,"visible":false}]},{"id":5892,"text":"What kind of protein makes more than 90% of organic matter of bone?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 143.","responses":[{"text":"Osteocalcin","correct":false,"visible":false},{"text":"Type I collagen","correct":true,"visible":false},{"text":"Bone morphogenic protein","correct":false,"visible":false},{"text":"Type V collagen","correct":false,"visible":false},{"text":"Osteopontin","correct":false,"visible":false}]},{"id":5893,"text":"Rupture of which of the following tendons causes acute muscular problem of leg in tennis player?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 759.","responses":[{"text":"Plantaris tendon","correct":true,"visible":false},{"text":"Tendo calcaneus tendon","correct":false,"visible":false},{"text":"Flexor hallucis longus tendon","correct":false,"visible":false},{"text":"Tibialis posterior tendon","correct":false,"visible":false},{"text":"Flexor digitorum longus tendon","correct":false,"visible":false}]},{"id":5894,"text":"Which of the following nerves of the sacral plexus does not leave the pelvis inferior to the piriformis, through the greater sciatic foramen?","explanation":null,"reference":"1. Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 485, 557.","responses":[{"text":"Nerve to quadratus femoris","correct":false,"visible":false},{"text":"Sciatic nerve","correct":false,"visible":false},{"text":"Superior gluteal nerve","correct":true,"visible":false},{"text":"Posterior cutaneous nerve of thigh","correct":false,"visible":false},{"text":"Inferior gluteal nerve","correct":false,"visible":false}]},{"id":5899,"text":"Paget's disease is an acquired disorder of bone. Which of the following statements regarding Paget's disease is correct?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1182-1183.","responses":[{"text":"It is common in children","correct":false,"visible":false},{"text":"It is due to a vitamin D deficiency","correct":false,"visible":false},{"text":"Histologically normal bone that is decreased in quantity is characteristic of this disease","correct":false,"visible":false},{"text":"A mosaic or jigsaw puzzle pattern on histology is characteristic of this disease","correct":true,"visible":false},{"text":"It is more common in Pakistan than in the USA","correct":false,"visible":false}]},{"id":5900,"text":"Which of the following is incorrect regarding the posterior axio-appendicular group of muscles?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 167, 170.","responses":[{"text":"This group has further three sub-groups","correct":false,"visible":false},{"text":"One of its sub-groups is the deep posterior axio-appendicular muscles","correct":false,"visible":false},{"text":"Examples of this group includes the levator scapulae and rhomboids","correct":false,"visible":false},{"text":"It includes the intrinsic shoulder muscles","correct":false,"visible":false},{"text":"They are also called the thoracoappendicular muscles","correct":true,"visible":false}]},{"id":5901,"text":"Which of the following structures passes superficial to the flexor retinaculum?","explanation":null,"reference":"Halliday NL, Chung HM. BRS: Gross Anatomy. 9th ed. Wolters Kluwer; 2019: 306.","responses":[{"text":"Flexor carpi radialis","correct":false,"visible":false},{"text":"Flexor digitorum superficialis","correct":false,"visible":false},{"text":"Flexor carpi ulnaris","correct":false,"visible":false},{"text":"Ulnar artery","correct":true,"visible":false},{"text":"Flexor carpi longus","correct":false,"visible":false}]},{"id":5902,"text":"The intercostobrachial nerve is a branch of which of the following?","explanation":null,"reference":"Herekar R, Bordoni B, Daly DT. Anatomy, shoulder and upper limb, intercostobrachial nerves. StatPearls. Published 2022. Accessed September 19, 2022. http://www.ncbi.nlm.nih.gov/books/NBK557619/","responses":[{"text":"Lower trunk of brachial plexus","correct":false,"visible":false},{"text":"Medial cord","correct":false,"visible":false},{"text":"1st intercostal nerve","correct":false,"visible":false},{"text":"2nd intercostal nerve","correct":true,"visible":false},{"text":"3rd intercostal nerve","correct":false,"visible":false}]},{"id":5903,"text":"Which of the following muscles of the shoulder region is a powerful lateral rotator of the shoulder joint?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 271.","responses":[{"text":"Subscapularis","correct":false,"visible":false},{"text":"Teres minor","correct":false,"visible":false},{"text":"Teres major","correct":false,"visible":false},{"text":"Infraspinatus","correct":true,"visible":false},{"text":"Supraspinatus","correct":false,"visible":false}]},{"id":5904,"text":"Deficiency of which of the following vitamins causes incomplete mineralization of bone leading to soft bone formation?","explanation":null,"reference":"Sahay M, Sahay R. Rickets–vitamin D deficiency and dependency. Indian Journal of Endocrinology and Metabolism. Published 2012. Accessed September 19, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3313732/","responses":[{"text":"Vitamin E","correct":false,"visible":false},{"text":"Vitamin D","correct":true,"visible":false},{"text":"Vitamin A","correct":false,"visible":false},{"text":"Vitamin C","correct":false,"visible":false},{"text":"Vitamin B","correct":false,"visible":false}]},{"id":5905,"text":"A 69-year-old man presents to the outpatient department with noted increasing back and leg pain for the past 3 years. He informs about serious difficulty in hearing from the left ear. He has recently been diagnosed with orthopnea and pedal edema. On physical examination, he is seen to have decreased range of motion at the hips. Radiographs reveal bony sclerosis of the sacroiliac, lower vertebral, and upper tibial regions. Laboratory studies show a serum alkaline phosphatase of 264 U/L. Which of the following conditions is he most likely to have?","explanation":null,"reference":null,"responses":[{"text":"Vitamin D deficiency","correct":false,"visible":false},{"text":"Renal failure with renal osteodystrophy","correct":false,"visible":false},{"text":"Metastatic adenocarcinoma","correct":false,"visible":false},{"text":"Osteoporosis","correct":false,"visible":false},{"text":"Paget's disease of bone","correct":true,"visible":false}]},{"id":5906,"text":"Which of the following bone does not give attachment to the triceps brachii muscle?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 205.","responses":[{"text":"Scapula","correct":false,"visible":false},{"text":"Humerus","correct":false,"visible":false},{"text":"Clavicle","correct":true,"visible":false},{"text":"Ulna","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":5907,"text":"Which one of the following fibers has maximum conduction velocity:","explanation":null,"reference":"Costanzo LS. BRS: Physiology. 7th ed. Wolters Kluwer; 2019: 39.","responses":[{"text":"Aγ fibers","correct":false,"visible":false},{"text":"Aβ fibers","correct":false,"visible":false},{"text":"C fibers","correct":false,"visible":false},{"text":"Aα fibers","correct":true,"visible":false},{"text":"AΔ fibers","correct":false,"visible":false}]},{"id":5908,"text":"Which of the following is incorrect regarding boundaries of the cubital fossa?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 209.","responses":[{"text":"Base ⟶ Imaginary line between two condyles","correct":false,"visible":false},{"text":"Medially ⟶ Palmaris longus","correct":true,"visible":false},{"text":"Floor ⟶ Brachialis and supinator","correct":false,"visible":false},{"text":"Apex ⟶ Meeting point of lateral and medial boundaries","correct":false,"visible":false},{"text":"Laterally ⟶ Brachoradialis","correct":false,"visible":false}]},{"id":5909,"text":"The deltoid muscle is innervated by which of the following nerve?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 174.","responses":[{"text":"Accessory","correct":false,"visible":false},{"text":"Dorsal scapular","correct":false,"visible":false},{"text":"Thoracodorsal","correct":false,"visible":false},{"text":"Subscapular","correct":false,"visible":false},{"text":"Axillary","correct":true,"visible":false}]},{"id":5910,"text":"Which of the following is the thin membrane that encloses a skeletal muscle fibre?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 79.","responses":[{"text":"Actin","correct":false,"visible":false},{"text":"Sarcolemma","correct":true,"visible":false},{"text":"Myofibril","correct":false,"visible":false},{"text":"Sarcomere","correct":false,"visible":false},{"text":"Myosin","correct":false,"visible":false}]},{"id":5911,"text":"Which of the following muscle is affected incase of injury to median nerve?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 204, 205, 218, 221.","responses":[{"text":"Triceps brachii","correct":false,"visible":false},{"text":"Flexor carpi radialis","correct":true,"visible":false},{"text":"Biceps brachii","correct":false,"visible":false},{"text":"Supinator","correct":false,"visible":false},{"text":"Brachialis","correct":false,"visible":false}]},{"id":5938,"text":"Which of the following muscles is a powerful adductor and medial rotator of the arm?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 167.","responses":[{"text":"Teres major","correct":false,"visible":false},{"text":"Pectoralis minor","correct":false,"visible":false},{"text":"Pectoralis major","correct":true,"visible":false},{"text":"Subscapularis","correct":false,"visible":false},{"text":"Teres minor","correct":false,"visible":false}]},{"id":5939,"text":"On which organ(s) does the parathyroid hormone act directly in order to increase the serum calcium levels?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 1002.","responses":[{"text":"Kidney","correct":false,"visible":false},{"text":"Bones and kidneys both","correct":true,"visible":false},{"text":"Intestine","correct":false,"visible":false},{"text":"Skeletal muscle","correct":false,"visible":false},{"text":"Bone","correct":false,"visible":false}]},{"id":5992,"text":"Which of the following nerves supply the teres minor muscle?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 174.","responses":[{"text":"Axillary nerve","correct":true,"visible":false},{"text":"Suprascapular nerve","correct":false,"visible":false},{"text":"Spinal part of accessory nerve","correct":false,"visible":false},{"text":"Pectoral nerve","correct":false,"visible":false},{"text":"Subscapular nerve","correct":false,"visible":false}]},{"id":5994,"text":"Which of the following is the most common nerve to be injured in the lower limb?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 764.","responses":[{"text":"Femoral nerve","correct":false,"visible":false},{"text":"Saphenous nerve","correct":false,"visible":false},{"text":"Common peroneal nerve","correct":true,"visible":false},{"text":"Obturator nerve","correct":false,"visible":false},{"text":"Tibial nerve","correct":false,"visible":false}]},{"id":5995,"text":"Which of the following muscles is innervated by the suprascapular nerve?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 174.","responses":[{"text":"Teres minor","correct":false,"visible":false},{"text":"Pectoralis major","correct":false,"visible":false},{"text":"Pectoralis minor","correct":false,"visible":false},{"text":"Infraspinatus","correct":true,"visible":false},{"text":"Teres major","correct":false,"visible":false}]},{"id":5996,"text":"Which of the following nerves supply the flexor digitorum longus muscle?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 757.","responses":[{"text":"Deep peroneal nerve","correct":false,"visible":false},{"text":"Superficial peroneal nerve","correct":false,"visible":false},{"text":"Common peroneal nerve","correct":false,"visible":false},{"text":"Sciatic nerve","correct":false,"visible":false},{"text":"Tibial nerve","correct":true,"visible":false}]},{"id":20939,"text":"Which of the following is the most abundant amino acid in collagen and plays a role in its triple-helix structure?","explanation":"The third position of the polypeptide chain in collagen is occupied by **glycine** (Gly-X-Y), making it the **most abundant** amino acid in collagen. It has a small side chain, allowing for close packing of the **collagen** chains within the triple helical structure of collagen. This contributes to the stability and structure of collagen, the main structural protein in connective tissues.\r\n\r\n***\r\n\r\nProline is another amino acid found in collagen, but it is not less abundant than. Proline contributes to the unique structure of collagen by introducing kinks in the polypeptide chains.\r\n\r\nLysine, arginine, and histidine are not major constituents of collagen.","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 45.","responses":[{"text":"Histidine","correct":false,"visible":false},{"text":"Proline","correct":false,"visible":false},{"text":"Arginine","correct":false,"visible":false},{"text":"Lysine","correct":false,"visible":false},{"text":"Glycine","correct":true,"visible":false}]}
]

